import java.util.ArrayList;

public class Main {
    enum Category { ELECTRONICS, FOOD, CLOTHING }

    record Product(String name, Category cat, double price) {}

    public static void main(String[] args) {
        ArrayList<Product> inv = new ArrayList<>();
        inv.add(new Product("Headphones", Category.ELECTRONICS, 1200.0));
        inv.add(new Product("Rice 5kg", Category.FOOD, 320.0));
        inv.add(new Product("T-Shirt", Category.CLOTHING, 450.0));
        inv.add(new Product("USB Cable", Category.ELECTRONICS, 150.0));

        System.out.println("=== Full Inventory ===");
        for (Product p : inv) {
            System.out.println(p.name() + " [" + p.cat() + "] - Rs." + p.price());
        }

        System.out.println("\n=== Under Rs.500 ===");
        int count = 0;
        for (Product p : inv) {
            if (p.price() < 500) {
                System.out.println("- " + p.name() + " (Rs." + p.price() + ")");
                count++;
            }
        }
        System.out.println(count + " affordable item(s)");
    }
}

