public class Main {
    public static void main(String[] args) {
        Robot r = new Robot("Bolt", Direction.NORTH);
        System.out.println(r);
        System.out.println(r.name() + " is facing " + r.facing());

        switch (r.facing()) {
            case NORTH -> System.out.println("Heading up! ⬆️");
            case EAST -> System.out.println("Heading right! ➡️");
            case SOUTH -> System.out.println("Heading down! ⬇️");
            case WEST -> System.out.println("Heading left! ⬅️");
        }
    }
}

enum Direction { NORTH, EAST, SOUTH, WEST }

record Robot(String name, Direction facing) {}
